function _slugify(s){return s.toLowerCase().replace(/[áà]/g,'a').replace(/[éè]/g,'e').replace(/[íì]/g,'i').replace(/[óò]/g,'o').replace(/[úù]/g,'u').replace(/ñ/g,'n').replace(/ã/g,'a').replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');}
