// Crear overlay de animación de análisis
function _kfShowAnalyzing(){
  var el=document.getElementById("kfAnalyzingOverlay");
  if(el){el.style.display="flex";return;}
  el=document.createElement("div");
  el.id="kfAnalyzingOverlay";
  el.innerHTML=`
    <div style="background:#fff;border-radius:20px;padding:2rem 2.5rem;text-align:center;box-shadow:0 8px 40px rgba(0,0,0,.28);max-width:300px;width:90%;">
      <div style="width:140px;height:140px;margin:0 auto 1.2rem;position:relative;">
        <!-- Lupa de Kit Finder estática -->
        <img src="images/logo_lupa_new.png" style="position:absolute;inset:0;width:140px;height:140px;object-fit:contain;z-index:2;" alt=""/>
        <!-- Balón girando clippeado al cristal circular de la lupa -->
        <div style="position:absolute;top:18px;left:48px;width:44px;height:44px;border-radius:50%;overflow:hidden;z-index:1;">
          <img src="images/ball-spin.png" style="width:44px;height:44px;animation:kfBallSpin 0.9s linear infinite;" alt=""/>
        </div>
      </div>
      <p id="kfAnalyzingMsg" style="font-size:15px;font-weight:700;color:#1e2530;margin-bottom:5px;">Analysing your shirt…</p>
      <p id="kfAnalyzingDetail" style="font-size:13px;color:#9aa3ad;">Identifying team, season &amp; version</p>
    </div>`;
  el.style.cssText="display:flex;position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:99999;align-items:center;justify-content:center;";
  if(!document.getElementById("kfSpinStyle")){
    var s=document.createElement("style");
    s.id="kfSpinStyle";
    s.textContent="@keyframes kfBallSpin{0%{transform:rotate(0deg)}100%{transform:rotate(360deg)}}";
    document.head.appendChild(s);
  }
  document.body.appendChild(el);
}
function _kfUpdateAnalyzing(msg,detail){
  var m=document.getElementById("kfAnalyzingMsg");
  var d=document.getElementById("kfAnalyzingDetail");
  if(m)m.textContent=msg;
  if(d&&detail)d.textContent=detail;
}
function _kfHideAnalyzing(){
  var el=document.getElementById("kfAnalyzingOverlay");
  if(el)el.style.display="none";
}

async function kfSearchByImage(input){
  var file=input.files[0];
  if(!file)return;
  input.value="";

  _kfShowAnalyzing();
  _kfUpdateAnalyzing("Reading image...","Preparing photo for analysis");

  try{
    var base64=await new Promise(function(resolve,reject){
      var reader=new FileReader();
      reader.onload=function(e){resolve(e.target.result.split(",")[1]);};
      reader.onerror=reject;
      reader.readAsDataURL(file);
    });

    _kfUpdateAnalyzing("Identifying shirt...","Analysing team, season & version");

    var response=await fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{
        "Content-Type":"application/json",
        "x-api-key":["sk-ant-api03-7vpD16ajp7SIbrSNLdZhvRE","tgwNZeP6WgUk5bk69gbrQ6XxPZEY7fyUQWLV","0Ss2ego4OVW7iBbBl6JPe11ROzg-PWQF_AAA"].join(""),
        "anthropic-version":"2023-06-01",
        "anthropic-dangerous-direct-browser-access":"true"
      },
      body:JSON.stringify({
        model:"claude-haiku-4-5-20251001",
        max_tokens:300,
        messages:[{
          role:"user",
          content:[
            {
              type:"image",
              source:{type:"base64",media_type:file.type||"image/jpeg",data:base64}
            },
            {
              type:"text",
              text:"You are an expert in football/soccer shirts from all eras and countries. Analyze this image. Use every clue: badge, sponsor text (Sharp, Opel, JVC, Carlsberg, Parmalat, SEAT, Teka...), manufacturer (Adidas, Nike, Umbro, Kappa, Hummel...), colors, patterns, collar, player name or number. Always give your best guess for the team. Reply ONLY with a valid JSON object, no markdown: {\"team\":\"team name\",\"version\":\"home or away or third or empty\",\"year\":\"year or season or empty\",\"brand\":\"manufacturer or empty\",\"player\":\"player name or empty\",\"number\":\"number or empty\",\"query\":\"3-5 word search query\"}"
            }
          ]
        }]
      })
    });

    var data=await response.json();
    if(!response.ok||data.error){throw new Error((data.error&&data.error.message)||"Vision error");}

    var text=(data.content&&data.content[0]&&data.content[0].text)||"";
    var parsed;
    try{
      var match=text.match(/\{[\s\S]*\}/);
      parsed=match?JSON.parse(match[0]):{query:text.trim().slice(0,60)};
    }catch(e){
      parsed={query:text.trim().slice(0,60)};
    }

    _kfUpdateAnalyzing("Match found!","Searching across 80+ stores");

    // Construir query principal
    var parts=[];
    if(parsed.team)parts.push(parsed.team);
    if(parsed.version&&parsed.version!=="home")parts.push(parsed.version);
    if(parsed.year)parts.push(parsed.year);
    if(parsed.brand&&!parsed.team)parts.push(parsed.brand);
    if(parsed.player)parts.push(parsed.player);

    var query=parts.length>0?parts.join(" "):(parsed.query||"");
    query=query.trim();

    if(query.length<2){
      _kfHideAnalyzing();
      alert("Could not identify the shirt. Try a clearer photo showing the front of the shirt.");
      return;
    }

    // Generar variantes de año y temporada
    var searchTerms=[query];
    if(parsed.team&&parsed.year){
      var team=parsed.team;
      var yrStr=String(parsed.year);
      // Extraer años del string (ej: "1998-1999", "1998/99", "1998")
      var y1=null,y2=null;
      var mFull=yrStr.match(/(\d{4})[\-\/](\d{4})/);
      var mShort=yrStr.match(/(\d{4})[\-\/](\d{2})/);
      var mSingle=yrStr.match(/^(\d{4})$/);
      if(mFull){y1=parseInt(mFull[1]);y2=parseInt(mFull[2]);}
      else if(mShort){y1=parseInt(mShort[1]);y2=y1+1;}
      else if(mSingle){y1=parseInt(mSingle[1]);y2=y1+1;}

      if(y1&&y2){
        var y2s=String(y2).slice(-2);
        // Variantes: "Stuttgart 1998", "Stuttgart 1999", "Stuttgart 98/99", "Stuttgart 1998/99", "Stuttgart 1998-99", "Stuttgart 1998/1999", "Stuttgart 1998-1999"
        [
          team+" "+y1,
          team+" "+y2,
          team+" "+y2s+"/"+String(y2+1).slice(-2),
          team+" "+y1+"/"+y2s,
          team+" "+y1+"-"+y2s,
          team+" "+y1+"/"+y2,
          team+" "+y1+"-"+y2
        ].forEach(function(v){if(searchTerms.indexOf(v)<0)searchTerms.push(v);});
      }
    }

    setTimeout(function(){
      _kfHideAnalyzing();
      // Limpiar los buscadores - no mostrar texto
      var ls=document.getElementById("landingSearch");
      var rs=document.getElementById("resultsSearch");
      if(ls)ls.value="";
      if(rs)rs.value="";
      // Buscar con todas las variantes
      triggerSearch(searchTerms.join(" "));
    },800);

  }catch(err){
    _kfHideAnalyzing();
    alert("Image search failed: "+err.message);
  }
}
